/**
 * 通过文件名后缀，为其匹配正确的 icon
 */
import * as React from 'react';
import FilePdfColorful from '@universe-design/icons-react/FilePdfColorful';
import FileImageColorful from '@universe-design/icons-react/FileImageColorful';
import FileVideoColorful from '@universe-design/icons-react/FileVideoColorful';
import FileExcelColorful from '@universe-design/icons-react/FileExcelColorful';
import FileAudioColorful from '@universe-design/icons-react/FileAudioColorful';
import FileZipColorful from '@universe-design/icons-react/FileZipColorful';
import FileTextColorful from '@universe-design/icons-react/FileTextColorful';
import FileDocColorful from '@universe-design/icons-react/FileDocColorful';
import FilePptColorful from '@universe-design/icons-react/FilePptColorful';
import FileAndroidColorful from '@universe-design/icons-react/FileAndroidColorful';
import FileSketchColorful from '@universe-design/icons-react/FileSketchColorful';
import FilePsColorful from '@universe-design/icons-react/FilePsColorful';
import FileAiColorful from '@universe-design/icons-react/FileAiColorful';
import FileIosColorful from '@universe-design/icons-react/FileIosColorful';
import FileUnknowColorful from '@universe-design/icons-react/FileUnknowColorful';
import pull from 'lodash/pull';
import concat from 'lodash/concat';
import memoize from 'lodash/memoize';
import type { UploadFile } from '../uploadFile/interface';
import baseExtensionMeta from './extension-meta';

const commonMimeList = {
  image: {
    extensions: pull(baseExtensionMeta.image, 'psd'),
    icon: <FileImageColorful />,
  },
  video: {
    extensions: concat(baseExtensionMeta.video, 'rmvb', 'rm'),
    icon: <FileVideoColorful />,
  },
  audio: {
    extensions: baseExtensionMeta.audio,
    icon: <FileAudioColorful />,
  },
  text: {
    extensions: pull(baseExtensionMeta.text, 'csv'),
    icon: <FileTextColorful />,
  },
  word: {
    extensions: ['doc', 'dot', 'docx', 'dotx'],
    icon: <FileDocColorful />,
  },
  excel: {
    extensions: ['xls', 'xlt', 'xlsx', 'xltx', 'csv', 'xlsm'],
    icon: <FileExcelColorful />,
  },
  ppt: {
    extensions: ['ppt', 'pptx', 'ppsx', 'ppam', 'potx'],
    icon: <FilePptColorful />,
  },
  zip: {
    extensions: ['zip', 'rar', 'tar', '7z'],
    icon: <FileZipColorful />,
  },
  pdf: {
    extensions: ['pdf'],
    icon: <FilePdfColorful />,
  },
  ai: {
    extensions: ['ai'],
    icon: <FileAiColorful />,
  },
  psd: {
    extensions: ['psd'],
    icon: <FilePsColorful />,
  },
  sketch: {
    extensions: ['sketch'],
    icon: <FileSketchColorful />,
  },
  apk: {
    extensions: ['apk'],
    icon: <FileAndroidColorful />,
  },
  aep: {
    extensions: ['aep'],
    icon: <FileIosColorful />,
  },
};

const getExtensionIconMap = memoize(() => {
  const extensionIconMap = new Map<string, React.ReactNode>();
  Object.values(commonMimeList).forEach(type =>
    type.extensions.forEach(extension => {
      extensionIconMap.set(extension, type.icon);
    }),
  );

  return extensionIconMap;
});

function getExtension(filename: string): string {
  return filename.replace(/.+\./, '').toLowerCase();
}

export default function getFileIcon(file: UploadFile) {
  const name = file.name || file.fileName;
  if (!name) {
    return;
  }
  const ext = getExtension(name);

  const map = getExtensionIconMap();
  return map.get(ext) || <FileUnknowColorful />;
}
